-- =============================================================================
-- Opsy demo seed for Supabase SQL editor (PostgreSQL)
-- Generated by: node scripts/generate-demo-supabase-seed.js
-- Source: data/demo-properties.json
--
-- Logins (local auth / users table):
--   Agent:     agent@opsy.com / 12345678
--   Homeowner: demo.homeowner.001@opsy.local … .100 / 12345678
--
-- Safe to re-run: uses ON CONFLICT DO NOTHING where possible;
--   re-running after partial failure may skip some rows — prefer a clean DB or delete demo rows.
-- This does NOT use Supabase Auth (auth.users); your API must use the `users` table.
-- If row-level security (RLS) is enabled on these tables, run as a role that bypasses RLS
-- (e.g. postgres) or temporarily relax policies for this seed.
--
-- Property photos are full https URLs (Unsplash). The backend presigned-URL helper
-- passes through http(s) URLs, so main_photo_url is populated automatically.
-- =============================================================================

BEGIN;

-- ---- Agent user ----
INSERT INTO users (email, password_hash, name, phone, role, contact_id, is_active, auth_provider, email_verified, avatar_url)
VALUES (
  'agent@opsy.com',
  '$2b$12$klmp4apMR66vVasb9Zd6xOmBqVtZObGriwUiSTHh426pri.HgUekq',
  'Jordan Agent',
  '2065550000',
  'agent'::user_role,
  0,
  true,
  'local',
  true,
  'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&fit=crop&q=80'
)
ON CONFLICT (email) DO UPDATE SET
  password_hash = EXCLUDED.password_hash,
  name = EXCLUDED.name,
  phone = EXCLUDED.phone,
  role = EXCLUDED.role,
  is_active = EXCLUDED.is_active,
  avatar_url = EXCLUDED.avatar_url,
  email_verified = EXCLUDED.email_verified,
  updated_at = NOW();

